"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[53],{1109:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","label":"Real Decentralized Compute Network","href":"/","docId":"introduction"},{"type":"category","label":"Developers","items":[{"type":"link","label":"First App Deployment","href":"/developers/deploy-first-app","docId":"developers/deploy-first-app"},{"type":"link","label":"Deployment Creation","href":"/developers/deployment-creation","docId":"developers/deployment-creation"},{"type":"link","label":"Deployment Runtime Environment","href":"/developers/deployment-runtime-environment","docId":"developers/deployment-runtime-environment"},{"type":"link","label":"Deployments On Demand","href":"/developers/on-demand-deployments","docId":"developers/on-demand-deployments"},{"type":"link","label":"How to run an LLM on Acurast","href":"/developers/llm-on-acurast","docId":"developers/llm-on-acurast"}],"collapsed":false,"collapsible":true},{"type":"link","label":"Acurast Processors","href":"/acurast-processors","docId":"acurast-processors"},{"type":"category","label":"Acurast Protocol","items":[{"type":"link","label":"Acurast Orchestrator","href":"/acurast-orchestrator","docId":"acurast-orchestrator"},{"type":"category","label":"Architecture","items":[{"type":"link","label":"Overview","href":"/acurast-protocol/architecture/architecture","docId":"acurast-protocol/architecture/architecture"},{"type":"link","label":"End-to-End Deployment Execution","href":"/acurast-protocol/architecture/end-to-end","docId":"acurast-protocol/architecture/end-to-end"},{"type":"link","label":"Application Layer","href":"/acurast-protocol/architecture/application-layer","docId":"acurast-protocol/architecture/application-layer"},{"type":"link","label":"Execution Layer","href":"/acurast-protocol/architecture/execution-layer","docId":"acurast-protocol/architecture/execution-layer"},{"type":"link","label":"Consensus Layer","href":"/acurast-protocol/architecture/consensus-layer","docId":"acurast-protocol/architecture/consensus-layer"},{"type":"link","label":"Instances","href":"/acurast-protocol/architecture/instances","docId":"acurast-protocol/architecture/instances"}],"collapsed":false,"collapsible":true},{"type":"link","label":"Node Setup","href":"/acurast-protocol/node-setup","docId":"acurast-protocol/node-setup"}],"collapsed":true,"collapsible":true},{"type":"link","label":"Ecosystems & Integrations","href":"/integrations","docId":"integrations"},{"type":"link","label":"Networks","href":"/networks","docId":"networks"},{"type":"link","label":"Wallets","href":"/wallets","docId":"wallets"},{"type":"link","label":"Tokenomics","href":"/tokenomics","docId":"tokenomics"}]},"docs":{"acurast-orchestrator":{"id":"acurast-orchestrator","title":"Acurast Orchestrator","description":"The Acurast Orchestrator is a centerpiece of the consensus layer, combining the orchestration (i.e., the scheduling of deployments and enabling the liquid matching) of the Processor\u2019s computational resources and Developers. The orchestrator plays an essential role in the definition, agreement, and enforcement of value exchange between processors and developers.","sidebar":"docs"},"acurast-processors":{"id":"acurast-processors","title":"Acurast Processors","description":"Acurast Processors are the infrastructure providers for Acurast\'s decentralized compute network. Processors provide the compute power of their phone and are used by developers to run their Deployments.","sidebar":"docs"},"acurast-protocol/architecture/application-layer":{"id":"acurast-protocol/architecture/application-layer","title":"Application Layer","description":"In the Internet of today, almost every application relies heavily on auxiliary systems. Whether external APIs are used for authentication, basic infrastructure (hosting), data availability, reliance, which can benefit from extending or replacing services and core elements with confidential applications, essentially eliminating a host of threat events. The possibilities with Acurast are near-endless since today\'s centralized Internet is heavily centralized both logically and in terms of trust anchors.","sidebar":"docs"},"acurast-protocol/architecture/architecture":{"id":"acurast-protocol/architecture/architecture","title":"Overview","description":"Acurast separates the consensus, execution, and application layer (c.f., Fig. 1).","sidebar":"docs"},"acurast-protocol/architecture/consensus-layer":{"id":"acurast-protocol/architecture/consensus-layer","title":"Consensus Layer","description":"The Permissionless Consensus layer forms the base of the Acurast protocol and is based on a variant of the Nominated Proof-of-Stake (NPoS) algorithm [1]. Unlike traditional Proof-of-Stake (PoS) networks, there are validators and nominators in NPoS. Block validators verify transactions to be included in the next block, similar to traditional PoS block validators. The key difference is that instead of being randomly chosen, the validator nodes are nominated by another node.","sidebar":"docs"},"acurast-protocol/architecture/end-to-end":{"id":"acurast-protocol/architecture/end-to-end","title":"End-to-End Deployment Execution","description":"Acurast introduces a paradigm shift in verifiable and confidential computation, advancing the way decentralized applications are developed and deployed. To emphasize the inner workings of Acurast, the following description follows a deployment from definition and deployment to completion (c.f., Fig. 1).","sidebar":"docs"},"acurast-protocol/architecture/execution-layer":{"id":"acurast-protocol/architecture/execution-layer","title":"Execution Layer","description":"Acurast\'s execution layer is modular, allowing the flexible selection of runtimes according to the requirements of the use-case and the deployment, respectively. Decoupling the execution layer from the consensus and application layer allows the long-term evolution of runtimes, avoiding dependency lock-ins. Additionally, it ensures the highest level of service and confidentiality because security models can iteratively evolve with upgrades as novel threats emerge or new requirements arise.","sidebar":"docs"},"acurast-protocol/architecture/instances":{"id":"acurast-protocol/architecture/instances","title":"Instances","description":"Acurast will bootstrap three distinct networks: (a) the Acurast Testnet, (b) the Acurast Canary, and (c) the Acurast Mainnet.","sidebar":"docs"},"acurast-protocol/node-setup":{"id":"acurast-protocol/node-setup","title":"Node Setup","description":"Step by step guide on how to setup an Acurast node for the Rococo testnet.","sidebar":"docs"},"developers/create-address":{"id":"developers/create-address","title":"Create Address","description":"This guide explains how to create an address with Talisman wallet. To install the browser extensions, follow their setup instructions or checkout their walkshrough video."},"developers/deploy-first-app":{"id":"developers/deploy-first-app","title":"First App Deployment","description":"Introduction","sidebar":"docs"},"developers/deploy-first-app-quest":{"id":"developers/deploy-first-app-quest","title":"First App Deployment (Console)","description":"Introduction"},"developers/deployment-creation":{"id":"developers/deployment-creation","title":"Deployment Creation","description":"Follow the steps in first app deployment if you want to deploy apps with the Acurast CLI.","sidebar":"docs"},"developers/deployment-runtime-environment":{"id":"developers/deployment-runtime-environment","title":"Deployment Runtime Environment","description":"The deployment\'s script running on Processors has access to the following a set of APIs.","sidebar":"docs"},"developers/llm-on-acurast":{"id":"developers/llm-on-acurast","title":"How to run an LLM on Acurast","description":"Introduction","sidebar":"docs"},"developers/on-demand-deployments":{"id":"developers/on-demand-deployments","title":"Deployments On Demand","description":"On demand deployments are special kind of deployments that can be used to access a processor on demand from a dapp. This is achieved by having the deployment open a websocket connection to the acurast websocket service and setup handlers to process incoming messages.","sidebar":"docs"},"integrations":{"id":"integrations","title":"Ecosystems & Integrations","description":"Acurast is built with interoperability at its core and is able to support various Web3 ecosystems and has multiple ways of being integrated within various environments such as EVM, WASM, Substrate and others.","sidebar":"docs"},"introduction":{"id":"introduction","title":"Real Decentralized Compute Network","description":"Acurast is the decentralized compu based on mobile phones.","sidebar":"docs"},"networks":{"id":"networks","title":"Networks","description":"A list of all related core infrastrucuture for each deployed Acurast network. More details on the functionalities of each network can be found in the Protocol Architecture \u2197","sidebar":"docs"},"tokenomics":{"id":"tokenomics","title":"Tokenomics","description":"Acurast is the decentralized compute network designed to power the emerging decentralized compute economy by aligning developers, compute providers, and end-users around shared incentives.","sidebar":"docs"},"wallets":{"id":"wallets","title":"Wallets","description":"A list of wallets supporting Acurast:","sidebar":"docs"}}}')}}]);